ChatGPT extraction
This script implements the ChatGPT-based PDF abstraction workflow. It uses ellmer to send extracted PDF text to OpenAI’s model with a structured schema, while also maintaining job-status files, retry logic, checkpointed partial results, and final exports for downstream analysis.


Click to show/hide R Code
# ---- Libraries ----
library(ellmer)
library(tidyverse)
library(pdftools)
library(tibble)
library(purrr)
library(dplyr)
library(rstudioapi)


# ---- Set file folder ----
results_dir &lt;- "Results/ChatGPT"
dir.create(results_dir, recursive = TRUE, showWarnings = FALSE)

# ---- Optional Reset Prompt ----
if (interactive() && rstudioapi::isAvailable()) {
  reset_confirm &lt;- rstudioapi::showQuestion(
    title = "Reset Checkpoint Files",
    message = "Do you want to reset all previously saved progress (job queue, partial results, etc.)?",
    ok = "Reset Everything",
    cancel = "No, keep my files"
  )

  if (reset_confirm) {
    files_to_delete &lt;- file.path(results_dir, c(
      "job_status_ChatGPT.csv",
      "partial_results_ChatGPT.rds",
      "final_results_ChatGPT.csv",
      "final_results_ChatGPT.rds"
    ))
    deleted &lt;- file.remove(files_to_delete[file.exists(files_to_delete)])
    message("🧹 Reset complete. Deleted ", sum(deleted), " files.")
  } else {
    message("🔁 Continuing with existing progress files.")
  }
}

# ---- Optional Retry Failed Prompt ----
job_status_file &lt;- file.path(results_dir, "job_status_ChatGPT.csv")
if (file.exists(job_status_file) && interactive() && rstudioapi::isAvailable()) {
  retry_failed &lt;- rstudioapi::showQuestion(
    title = "Retry Previously Failed Jobs?",
    message = "Some jobs have failed after 5 attempts. Do you want to retry them again?",
    ok = "🔁 Yes, retry failed",
    cancel = "🚫 No, leave as failed"
  )

  if (isTRUE(retry_failed)) {
    job_status &lt;- read.csv(job_status_file, stringsAsFactors = FALSE)
    num_failed &lt;- sum(job_status$status == "failed")
    job_status$status[job_status$status == "failed"] &lt;- "retry"
    write.csv(job_status, job_status_file, row.names = FALSE)
    message("🔁 Reset ", num_failed, " failed jobs to 'retry'")
  } else {
    message("🚫 Failed jobs will remain skipped.")
  }
}

# ---- Setup ----
folder_path &lt;- "data-raw/PDFs"
pdf_files &lt;- list.files(folder_path, pattern = "\\.pdf$", full.names = TRUE)
files_df &lt;- tibble(full_path = pdf_files)

`%||%` &lt;- function(x, y) if (is.null(x)) y else x
estimate_tokens &lt;- function(text) ceiling(nchar(text) / 4)


#Pull schema from R script
source("R/abstract_schema.R")

chatgpt1 &lt;- chat_openai(
  model = "gpt-5.1",
  system_prompt = id_prompt("")
  )

# ---- Job Queue ----
if (!file.exists(job_status_file)) {
  job_status &lt;- tibble(
    full_path = files_df$full_path,
    filename = basename(files_df$full_path),
    status = "pending",
    retries = 0,
    last_attempt = as.POSIXct(NA)
  )
  write.csv(job_status, job_status_file, row.names = FALSE)
} else {
  job_status &lt;- read.csv(job_status_file, stringsAsFactors = FALSE)
  job_status$last_attempt &lt;- as.POSIXct(job_status$last_attempt)
}

# ---- Resume ----
partial_rds &lt;- file.path(results_dir, "partial_results_ChatGPT.rds")
results_list &lt;- if (file.exists(partial_rds)) {
  message("🔁 Resuming from saved results...")
  readRDS(partial_rds) %&gt;% split(seq_len(nrow(.)))
} else {
  list()
}

# ---- Global Counters ----
total_input_tokens &lt;&lt;- 0
total_output_tokens &lt;&lt;- 0
total_requests &lt;&lt;- 0
total_retries &lt;&lt;- 0

# ---- Main Extractor ----
extract_summary_row &lt;- function(pdf_path,
                                initial_max_chars = 240000,
                                min_chars = 5000,
                                initial_wait = 300,
                                max_wait = 1200,
                                max_retries = 5) {
  if (!file.exists(pdf_path)) {
    message("Skipping missing file: ", pdf_path)
    return(tibble(filename = basename(pdf_path)))
  }

  text_pages &lt;- pdftools::pdf_text(pdf_path)
  full_text &lt;- paste(text_pages, collapse = "\n")
  full_char_length &lt;- nchar(full_text)
  max_chars &lt;- min(full_char_length, initial_max_chars)
  wait_time &lt;- initial_wait
  retries &lt;- 0

  while (max_chars &gt;= min_chars && retries &lt;= max_retries) {
    input_text &lt;- substr(full_text, 1, max_chars)
    input_token_est &lt;- estimate_tokens(input_text)
    message(Sys.time(), " 🔄 Attempting ", basename(pdf_path), " with ~", input_token_est, " tokens")

    result &lt;- tryCatch({
      chatgpt1 &lt;- chat_openai(
        model = "gpt-5.1",
        system_prompt = id_prompt("")
      )
      chatgpt1$chat_structured(input_text, type = type_summary)
    }, error = function(e) {
      if (grepl("tokens per min|quota|429", e$message)) {
        message("⚠️ Rate limit or quota error. Waiting ", wait_time, "s")
        total_retries &lt;&lt;- total_retries + 1
        Sys.sleep(wait_time)
        return("RATE_LIMIT_RETRY")
      } else {
        message("❌ Error: ", e$message)
        return(structure("ERROR", class = "error"))
      }
    })

    if (identical(result, "RATE_LIMIT_RETRY")) {
      retries &lt;- retries + 1
      wait_time &lt;- min(wait_time * 1.5, max_wait)
      max_chars &lt;- floor(max_chars * 0.9)
      next
    }

    if (inherits(result, "error") || is.null(result)) {
      chatgpt1 &lt;- chat_openai(
        model = "gpt-5.1",
        system_prompt = id_prompt("")
      )
      fallback &lt;- chatgpt1$chat(input_text)
      output_token_est &lt;- estimate_tokens(fallback)
      total_output_tokens &lt;&lt;- total_output_tokens + output_token_est
      message("⚠️ Fallback preview:\n", substr(fallback, 1, 500))
      break
    }

    output_token_est &lt;- estimate_tokens(paste(result$title %||% "", result$journal %||% "", result$authors %||% ""))
    total_input_tokens &lt;&lt;- total_input_tokens + input_token_est
    total_output_tokens &lt;&lt;- total_output_tokens + output_token_est
    total_requests &lt;&lt;- total_requests + 1

    message("✅ Success: ", basename(pdf_path))
    return(as_tibble_row(
      c(
        list(filename = basename(pdf_path), text = input_text, char_length = nchar(input_text), raw_json = list(result)),
        map(result, ~ if (is.null(.x)) NA_character_ else paste(as.character(unlist(.x)), collapse = "; "))
      )
    ))
  }

  message("❌ Final failure for ", basename(pdf_path), " after ", retries, " retries.")
  tibble(filename = basename(pdf_path), text = substr(full_text, 1, min_chars), char_length = min_chars)
}

# ---- Main Loop ----
message("\n===== Starting ChatGPT PDF summarization =====")
message("Pending: ", sum(job_status$status == 'pending'))
message("Retry: ", sum(job_status$status == 'retry'))
message("Done: ", sum(job_status$status == 'done'))
message("Failed: ", sum(job_status$status == 'failed'))

for (i in seq_len(nrow(job_status))) {
  row &lt;- job_status[i, ]
  message("\n📄 Processing file ", i, "/", nrow(job_status), ": ", row$filename)

  if (row$status == "done") {
    message("⏭️ Skipping (done): ", row$filename)
    next
  }
  if (row$status == "failed") {
    message("⚠️ Skipping (failed): ", row$filename)
    next
  }

  result &lt;- extract_summary_row(row$full_path)

  if (!"authors" %in% names(result) || is.na(result$authors[1])) {
    job_status$retries[i] &lt;- job_status$retries[i] + 1
    job_status$status[i] &lt;- ifelse(job_status$retries[i] &gt;= 5, "failed", "retry")
  } else {
    job_status$status[i] &lt;- "done"
    results_list[[length(results_list) + 1]] &lt;- result
  }

  job_status$last_attempt[i] &lt;- Sys.time()
  message("💾 Saving checkpoint...")
  write.csv(job_status, job_status_file, row.names = FALSE)
  saveRDS(bind_rows(results_list), partial_rds)
  Sys.sleep(60)
}

# ---- Final Save ----
results_df &lt;- bind_rows(results_list)

# Flatten list-columns for CSV export
results_df_flat &lt;- results_df %&gt;%
  mutate(across(where(is.list), ~ sapply(.x, function(val) {
    if (is.null(val) || all(is.na(val))) return(NA_character_)
    if (length(val) == 0) return(NA_character_)
    paste(as.character(val), collapse = "; ")
  })))

# Save final outputs
write.csv(results_df_flat, file.path(results_dir, "final_results_ChatGPT.csv"))
saveRDS(results_df, file.path(results_dir, "final_results_ChatGPT.rds"))
write.csv(job_status, job_status_file)

# ---- Summary ----
cat("\n===== ✅ ChatGPT Job Summary =====\n")
cat("🧾 Total requests:      ", total_requests, "\n")
cat("🔡 Total input tokens:  ", total_input_tokens, "\n")
cat("📤 Total output tokens: ", total_output_tokens, "\n")
cat("🔁 Total retries:       ", total_retries, "\n")
cat("📂 Output written to:   final_results_ChatGPT.csv / .rds\n")

Google Gemini
This script implements the Google Gemini-based PDF abstraction workflow. It follows the same general strategy as the other model pipelines, using structured extraction with checkpointing and retry logic to support analysis of a large set of PDFs.


Click to show/hide R Code
# ---- Libraries ----
library(ellmer)
library(tidyverse)
library(pdftools)
library(rstudioapi)
library(purrr)

# Define folder for Gemini output files
results_dir &lt;- "Results/Gemini"
dir.create(results_dir, recursive = TRUE, showWarnings = FALSE)

# ---- Optional Reset Prompt ----
if (interactive() && rstudioapi::isAvailable()) {
  reset_confirm &lt;- rstudioapi::showQuestion(
    title = "Reset Gemini Files",
    message = "Reset all Gemini checkpoint and log files?",
    ok = "Yes, reset",
    cancel = "No, keep"
  )
  if (reset_confirm) {
    files_to_delete &lt;- file.path(results_dir, c(
      "processed_files_gemini.txt",
      "failed_files_gemini.txt",
      "summary_partial_gemini.rds",
      "summary_partial_gemini.csv",
      "summary_final_gemini.rds",
      "summary_output_gemini.csv",
      "type_summary_gemini_schema.rds",
      "job_status_Gemini.csv"
    ))
    deleted &lt;- file.remove(files_to_delete[file.exists(files_to_delete)])
    message("🧹 Deleted ", sum(deleted), " files.")
  }
}

# ---- Setup ----
folder_path &lt;- "data-raw/PDFs"
pdf_files &lt;- list.files(folder_path, pattern = "\\.pdf$", full.names = TRUE)

estimate_tokens &lt;- function(text) ceiling(nchar(text) / 4)

#Pull schema from R script
source("R/abstract_schema.R")

# ---- Job Queue Setup ----
job_file &lt;- file.path(results_dir, "job_status_Gemini.csv")
if (!file.exists(job_file)) {
  job_status &lt;- tibble(
    full_path = pdf_files,
    filename = basename(pdf_files),
    status = "pending",
    retries = 0,
    last_attempt = as.POSIXct(NA)
  )
  write_csv(job_status, job_file)
} else {
  job_status &lt;- read_csv(job_file, show_col_types = FALSE)
}

# ---- Resume Results ----
checkpoint_file &lt;- file.path(results_dir, "summary_partial_gemini.rds")
if (file.exists(checkpoint_file)) {
  results_list &lt;- readRDS(checkpoint_file)
} else {
  results_list &lt;- list()
}

# ---- Sync Job Status with Saved Results ----
done_filenames &lt;- names(results_list)
job_status &lt;- job_status %&gt;%
  mutate(
    status = ifelse(filename %in% done_filenames, "done", status)
  )

# ---- Global Counters ----
total_input_tokens &lt;- 0
total_output_tokens &lt;- 0
total_requests &lt;- 0
total_retries &lt;- 0

# ---- Summarizer Function ----
extract_summary_single &lt;- function(pdf_path, max_pages = 50, max_chars = 240000, max_retries = 6, global_pause = 15 * 60) {
  if (!file.exists(pdf_path)) {
    message("❌ File not found: ", pdf_path)
    return(NULL)
  }

  text_pages &lt;- pdftools::pdf_text(pdf_path)
  truncated_text &lt;- paste(text_pages[1:min(length(text_pages), max_pages)], collapse = "\n")
  truncated_text &lt;- substr(truncated_text, 1, max_chars)
  estimated_tokens &lt;- estimate_tokens(truncated_text)

  retries &lt;- 0
  backoff &lt;- c(60, 120, 180, 240, 300, 600)

  repeat {
    cat("📏 Estimated tokens:", estimated_tokens, "from", nchar(truncated_text), "chars\n")
    result &lt;- tryCatch({
      print(Sys.time())
      gemini1 &lt;- chat_google_gemini(
        model = "gemini-2.5-flash",
        system_prompt = id_prompt("")
      )

      gemini1$chat_structured(truncated_text, type = type_summary)
    }, error = function(e) {
      msg &lt;- conditionMessage(e)
      if (grepl("429|quota|rate limit", msg)) {
        wait_time &lt;- if (retries &lt; length(backoff)) backoff[retries + 1] else 900
        wait_time &lt;- runif(1, wait_time * 0.9, wait_time * 1.1)
        cat("⏳ Rate limit hit. Waiting", round(wait_time), "s (attempt", retries + 1, ")\n")
        Sys.sleep(wait_time)
        retries &lt;&lt;- retries + 1
        total_retries &lt;&lt;- total_retries + 1
        return("RETRY")
      } else {
        cat("❌ Unexpected error:", msg, "\n")
        return(NULL)
      }
    })

    if (identical(result, "RETRY")) {
      if (retries &gt;= max_retries) {
        cat("❌ Max retries reached\n")
        return(NULL)
      }
    } else {
      break
    }
  }

  if (is.null(result)) {
    fallback &lt;- gemini1$chat(truncated_text)
    cat("⚠️ Fallback preview:\n", substr(fallback, 1, 500), "\n")
    return(NULL)
  }

  result_list &lt;- result
  result_list$filename &lt;- basename(pdf_path)

  result_clean &lt;- result_list %&gt;% purrr::map_chr(~ {
    if (is.null(.x) || length(.x) == 0) return(NA_character_)
    if (is.atomic(.x) && length(.x) == 1) return(as.character(.x))
    if (is.atomic(.x) && length(.x) &gt; 1) return(paste(.x, collapse = ", "))
    return(as.character(.x))
  })

  output_tokens &lt;- estimate_tokens(paste(result_clean, collapse = " "))
  total_input_tokens &lt;&lt;- total_input_tokens + estimated_tokens
  total_output_tokens &lt;&lt;- total_output_tokens + output_tokens
  total_requests &lt;&lt;- total_requests + 1

  list(data = tibble::as_tibble_row(result_clean), token_count = estimated_tokens)
}

# ---- Main Loop ----
message("\n===== Starting Gemini PDF summarization =====")
message("Pending: ", sum(job_status$status == 'pending'))
message("Retry: ", sum(job_status$status == 'retry'))
message("Done: ", sum(job_status$status == 'done'))
message("Failed: ", sum(job_status$status == 'failed'))

for (i in seq_len(nrow(job_status))) {
  row &lt;- job_status[i, ]
  cat("\n[", i, "/", nrow(job_status), "]", row$filename, "\n")

  if (row$status %in% c("done", "failed")) {
    cat("⏭️ Skipping (status:", row$status, ")\n")
    next
  }

  result &lt;- extract_summary_single(row$full_path)

  if (!is.null(result)) {
    results_list[[row$filename]] &lt;- result$data
    job_status$status[i] &lt;- "done"
    wait_time &lt;- ceiling(result$token_count / 1000) * 10
    wait_time &lt;- runif(1, wait_time * 0.9, wait_time * 1.1)
    cat("🕒 Waiting", round(wait_time), "s...\n")
    Sys.sleep(wait_time)
  } else {
    job_status$retries[i] &lt;- job_status$retries[i] + 1
    job_status$status[i] &lt;- ifelse(job_status$retries[i] &gt;= 5, "failed", "retry")
  }

  job_status$last_attempt[i] &lt;- Sys.time()
  write_csv(job_status, job_file)
  saveRDS(results_list, checkpoint_file)
}

# ---- Final Save ----
final_df &lt;- bind_rows(results_list)
write_csv(final_df, file.path(results_dir, "summary_output_gemini.csv"))

message("\n===== Summary =====")
message("Total requests: ", total_requests)
message("Input tokens: ", total_input_tokens)
message("Output tokens: ", total_output_tokens)
message("Retries: ", total_retries)

Function that safely normalizes to logical
The PDF review dataset contains binary variables that may appear in different formats, including logical values and character encodings such as "yes", "no", "true", "false", "1", and "0". The convert_to_logical() function standardizes these inputs into TRUE, FALSE, or NA. This preprocessing step helps ensure that downstream comparisons between human and model-generated labels are performed on consistently formatted data.


Click to show/hide R Code
convert_to_logical &lt;- function(x) {
  if (is.logical(x)) return(x)

  x_clean &lt;- trimws(tolower(as.character(x)))

  case_when(
    x_clean %in% c("true", "yes", "1")  ~ TRUE,
    x_clean %in% c("false", "no", "0") ~ FALSE,
    TRUE ~ NA
  )
}

Function to create heatmap
The make_llm_agreement_heatmap() function creates a paper-by-variable heatmap showing how many of the three language models matched the human-reviewed label for each observation. It can optionally relabel variables using label_list, reorder rows and columns by average agreement, and customize the plot title and subtitle. This figure is used to visualize where model agreement was high, where it was mixed, and which variables were most difficult for the models to classify consistently.


Click to show/hide R Code
make_llm_agreement_heatmap &lt;- function(df,
                                       vars,
                                       paper_id_col = "filename",
                                       label_list = NULL,
                                       title = "LLM agreement heatmap",
                                       subtitle = "Each cell shows how many of 3 models matched the human label",
                                       low_to_high = TRUE,
                                       reorder = TRUE) {

  stopifnot(is.data.frame(df))
  stopifnot(is.character(vars))
  stopifnot(length(paper_id_col) == 1)

  if (!paper_id_col %in% names(df)) {
    stop("`paper_id_col` not found in `df`.")
  }

  needed_cols &lt;- c(
    unlist(purrr::map(vars, ~ c(
      paste0(.x, "_human"),
      paste0(.x, "_ChatGPT"),
      paste0(.x, "_claude"),
      paste0(.x, "_gemini")
    ))),
    paper_id_col
  )

  missing_cols &lt;- setdiff(needed_cols, names(df))
  if (length(missing_cols) &gt; 0) {
    stop(
      "These required columns are missing from `df`: ",
      paste(missing_cols, collapse = ", ")
    )
  }

  heatmap_df &lt;- purrr::map_dfr(vars, function(v) {
    human_col &lt;- paste0(v, "_human")
    chat_col  &lt;- paste0(v, "_ChatGPT")
    cla_col   &lt;- paste0(v, "_claude")
    gem_col   &lt;- paste0(v, "_gemini")

    pretty_label &lt;- if (!is.null(label_list) && v %in% names(label_list)) {
      unname(label_list[[v]])
    } else {
      v
    }

    tibble::tibble(
      paper_id = stringr::word(as.character(df[[paper_id_col]]), 1) |&gt;
        stringr::str_remove("\\.$"),
      variable = v,
      label = pretty_label,
      human = df[[human_col]],
      chat  = df[[chat_col]],
      cla   = df[[cla_col]],
      gem   = df[[gem_col]]
    ) |&gt;
      dplyr::mutate(
        chat_match = dplyr::if_else(is.na(human) | is.na(chat), NA_integer_, as.integer(human == chat)),
        cla_match  = dplyr::if_else(is.na(human) | is.na(cla),  NA_integer_, as.integer(human == cla)),
        gem_match  = dplyr::if_else(is.na(human) | is.na(gem),  NA_integer_, as.integer(human == gem)),
        n_models_scorable = rowSums(!is.na(dplyr::pick(chat_match, cla_match, gem_match))),
        n_models_correct  = rowSums(dplyr::pick(chat_match, cla_match, gem_match), na.rm = TRUE),
        n_models_correct  = dplyr::if_else(n_models_scorable == 0, NA_integer_, n_models_correct)
      )
  })

  if (reorder) {
    row_summary &lt;- heatmap_df |&gt;
      dplyr::group_by(paper_id) |&gt;
      dplyr::summarise(mean_models_correct = mean(n_models_correct, na.rm = TRUE), .groups = "drop")

    col_summary &lt;- heatmap_df |&gt;
      dplyr::group_by(label) |&gt;
      dplyr::summarise(mean_models_correct = mean(n_models_correct, na.rm = TRUE), .groups = "drop")

    if (low_to_high) {
      row_order &lt;- row_summary |&gt;
        dplyr::arrange(mean_models_correct) |&gt;
        dplyr::pull(paper_id)

      col_order &lt;- col_summary |&gt;
        dplyr::arrange(mean_models_correct) |&gt;
        dplyr::pull(label)
    } else {
      row_order &lt;- row_summary |&gt;
        dplyr::arrange(dplyr::desc(mean_models_correct)) |&gt;
        dplyr::pull(paper_id)

      col_order &lt;- col_summary |&gt;
        dplyr::arrange(dplyr::desc(mean_models_correct)) |&gt;
        dplyr::pull(label)
    }
  } else {
    row_order &lt;- df[[paper_id_col]] |&gt;
      as.character() |&gt;
      stringr::word(1) |&gt;
      stringr::str_remove("\\.$") |&gt;
      unique()

    col_order &lt;- purrr::map_chr(vars, function(v) {
      if (!is.null(label_list) && v %in% names(label_list)) {
        unname(label_list[[v]])
      } else {
        v
      }
    })
  }

  heatmap_df &lt;- heatmap_df |&gt;
    dplyr::mutate(
      paper_id = factor(paper_id, levels = rev(row_order)),
      label = factor(label, levels = col_order),
      n_models_correct_f = factor(as.character(n_models_correct), levels = c("0", "1", "2", "3"))
    )

  # invisible layer to force all 4 legend boxes to appear, using geom_tile
  legend_df &lt;- tibble::tibble(
    label = factor(rep(col_order[1], 4), levels = col_order),
    paper_id = factor(rep(rev(row_order)[1], 4), levels = levels(heatmap_df$paper_id)),
    n_models_correct_f = factor(c("0", "1", "2", "3"), levels = c("0", "1", "2", "3"))
  )

  ggplot2::ggplot(
    heatmap_df,
    ggplot2::aes(x = label, y = paper_id, fill = n_models_correct_f)
  ) +
    ggplot2::geom_tile(color = "white", linewidth = 0.25) +
    ggplot2::geom_tile(
      data = legend_df,
      ggplot2::aes(x = label, y = paper_id, fill = n_models_correct_f),
      inherit.aes = FALSE,
      alpha = 0,
      show.legend = TRUE
    ) +
    ggplot2::scale_fill_manual(
      values = c(
        "0" = "#b2182b",
        "1" = "#ef8a62",
        "2" = "#fddbc7",
        "3" = "#d1e5f0"
      ),
      breaks = c("0", "1", "2", "3"),
      drop = FALSE,
